/* ========================================
   BREW & BLOOM - MODERN COFFEE SHOP CSS
   Contemporary, Elegant, Responsive
   ======================================== */

/* CSS Custom Properties */
:root {
    /* Colors - Warm Coffee Palette */
    --color-primary: #6F4E37;
    --color-primary-dark: #5A3D2B;
    --color-primary-light: #8B6914;

    --color-secondary: #D4A574;
    --color-secondary-light: #E8C9A0;
    --color-secondary-lighter: #F5E6D3;

    --color-accent: #C75B39;
    --color-accent-dark: #A6442C;

    --color-cream: #FDF8F3;
    --color-white: #FFFFFF;
    --color-black: #1A1A1A;
    --color-dark: #2C2420;
    --color-gray: #6B6B6B;
    --color-gray-light: #E5E5E5;

    /* Gradients */
    --gradient-warm: linear-gradient(135deg, var(--color-secondary-light) 0%, var(--color-secondary) 100%);
    --gradient-dark: linear-gradient(135deg, var(--color-dark) 0%, var(--color-black) 100%);
    --gradient-coffee: linear-gradient(135deg, #3C2415 0%, #6F4E37 50%, #8B6914 100%);
    --gradient-hero: linear-gradient(135deg, #1A1A1A 0%, #3C2415 50%, #5A3D2B 100%);
    --gradient-overlay: linear-gradient(to bottom, rgba(26, 26, 26, 0.7) 0%, rgba(58, 36, 21, 0.9) 100%);

    /* Typography */
    --font-display: 'Playfair Display', Georgia, serif;
    --font-body: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;

    --font-size-xs: 0.75rem;
    --font-size-sm: 0.875rem;
    --font-size-base: 1rem;
    --font-size-lg: 1.125rem;
    --font-size-xl: 1.25rem;
    --font-size-2xl: 1.5rem;
    --font-size-3xl: 2rem;
    --font-size-4xl: 2.5rem;
    --font-size-5xl: 3.5rem;
    --font-size-6xl: 4rem;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    /* Spacing */
    --section-padding: 6rem;
    --container-max: 1280px;
    --container-padding: 1.5rem;

    /* Border Radius */
    --radius-sm: 0.375rem;
    --radius-md: 0.5rem;
    --radius-lg: 0.75rem;
    --radius-xl: 1rem;
    --radius-2xl: 1.5rem;
    --radius-full: 9999px;

    /* Shadows */
    --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
    --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
    --shadow-xl: 0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04);
    --shadow-glow: 0 0 30px rgba(212, 165, 116, 0.3);
    --shadow-card: 0 4px 20px rgba(0, 0, 0, 0.08);

    /* Transitions */
    --transition-fast: 0.15s ease;
    --transition-base: 0.3s ease;
    --transition-slow: 0.5s ease;
    --transition-bounce: 0.5s cubic-bezier(0.68, -0.55, 0.265, 1.55);

    /* Glass Effect */
    --glass-bg: rgba(255, 255, 255, 0.1);
    --glass-border: rgba(255, 255, 255, 0.2);
    --glass-blur: blur(12px);
    --glass-dark: rgba(26, 26, 26, 0.8);
}

/* Reset & Base */
*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html {
    scroll-behavior: smooth;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-base);
    line-height: 1.6;
    color: var(--color-dark);
    background-color: var(--color-cream);
    overflow-x: hidden;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

a {
    text-decoration: none;
    color: inherit;
    transition: color var(--transition-base);
}

ul, ol {
    list-style: none;
}

button {
    cursor: pointer;
    border: none;
    background: none;
    font-family: inherit;
}

/* Typography */
h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-display);
    font-weight: var(--font-weight-semibold);
    line-height: 1.2;
    color: var(--color-dark);
}

p {
    margin-bottom: 1rem;
}

/* Container */
.container {
    max-width: var(--container-max);
    margin: 0 auto;
    padding: 0 var(--container-padding);
}

/* ========================================
   NAVIGATION
   ======================================== */
.navbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    padding: 1rem 0;
    transition: all var(--transition-base);
}

.navbar.scrolled {
    background: rgba(255, 255, 255, 0.95);
    backdrop-filter: var(--glass-blur);
    box-shadow: var(--shadow-md);
    padding: 0.75rem 0;
}

.nav-container {
    max-width: var(--container-max);
    margin: 0 auto;
    padding: 0 var(--container-padding);
    display: flex;
    align-items: center;
    justify-content: space-between;
}

/* Logo */
.logo {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-family: var(--font-display);
    font-size: var(--font-size-xl);
    font-weight: var(--font-weight-semibold);
    color: var(--color-white);
    transition: color var(--transition-base);
}

.navbar.scrolled .logo {
    color: var(--color-dark);
}

.logo-icon {
    font-size: 1.5rem;
}

.logo-text {
    letter-spacing: -0.02em;
}

/* Nav Links */
.nav-links {
    display: flex;
    align-items: center;
    gap: 2rem;
}

.nav-link {
    color: rgba(255, 255, 255, 0.8);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    position: relative;
    padding: 0.5rem 0;
    transition: color var(--transition-base);
}

.navbar.scrolled .nav-link {
    color: var(--color-gray);
}

.nav-link::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 2px;
    background: var(--color-secondary);
    transition: width var(--transition-base);
}

.nav-link:hover,
.nav-link.active {
    color: var(--color-white);
}

.navbar.scrolled .nav-link:hover,
.navbar.scrolled .nav-link.active {
    color: var(--color-primary);
}

.nav-link:hover::after,
.nav-link.active::after {
    width: 100%;
}

/* Nav Actions */
.nav-actions {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.btn-cart {
    position: relative;
    color: var(--color-white);
    padding: 0.5rem;
    transition: color var(--transition-base), transform var(--transition-base);
}

.navbar.scrolled .btn-cart {
    color: var(--color-dark);
}

.btn-cart:hover {
    transform: scale(1.1);
}

.cart-count {
    position: absolute;
    top: -2px;
    right: -2px;
    width: 18px;
    height: 18px;
    background: var(--color-accent);
    color: white;
    font-size: 10px;
    font-weight: var(--font-weight-bold);
    border-radius: var(--radius-full);
    display: flex;
    align-items: center;
    justify-content: center;
}

.btn-order {
    background: var(--color-secondary);
    color: var(--color-dark);
    padding: 0.625rem 1.25rem;
    border-radius: var(--radius-full);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-semibold);
    transition: all var(--transition-base);
}

.btn-order:hover {
    background: var(--color-white);
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

.navbar.scrolled .btn-order {
    background: var(--color-primary);
    color: var(--color-white);
}

.navbar.scrolled .btn-order:hover {
    background: var(--color-primary-dark);
}

/* Mobile Toggle */
.mobile-toggle {
    display: none;
    flex-direction: column;
    gap: 5px;
    padding: 0.5rem;
}

.mobile-toggle span {
    display: block;
    width: 24px;
    height: 2px;
    background: var(--color-white);
    transition: all var(--transition-base);
}

.navbar.scrolled .mobile-toggle span {
    background: var(--color-dark);
}

/* ========================================
   HERO SECTION
   ======================================== */
.hero {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
    overflow: hidden;
    padding: 8rem 2rem 4rem;
}

.hero-bg {
    position: absolute;
    inset: 0;
    background: var(--gradient-hero);
}

.hero-overlay {
    position: absolute;
    inset: 0;
    background: url("data:image/svg+xml,%3Csvg viewBox='0 0 400 400' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E");
    opacity: 0.03;
}

/* Floating Shapes */
.floating-shapes {
    position: absolute;
    inset: 0;
    overflow: hidden;
    pointer-events: none;
}

.shape {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.4;
    animation: float 20s ease-in-out infinite;
}

.shape-1 {
    width: 600px;
    height: 600px;
    background: var(--color-secondary);
    top: -200px;
    right: -200px;
    animation-delay: 0s;
}

.shape-2 {
    width: 400px;
    height: 400px;
    background: var(--color-accent);
    bottom: -100px;
    left: -100px;
    animation-delay: -5s;
}

.shape-3 {
    width: 300px;
    height: 300px;
    background: var(--color-primary-light);
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    animation-delay: -10s;
}

@keyframes float {
    0%, 100% {
        transform: translate(0, 0) rotate(0deg);
    }
    33% {
        transform: translate(30px, -30px) rotate(120deg);
    }
    66% {
        transform: translate(-20px, 20px) rotate(240deg);
    }
}

/* Hero Content */
.hero-content {
    position: relative;
    z-index: 1;
    max-width: 800px;
    text-align: center;
    color: var(--color-white);
}

.hero-tagline {
    display: inline-block;
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.2em;
    text-transform: uppercase;
    color: var(--color-secondary);
    margin-bottom: 1.5rem;
    padding: 0.5rem 1rem;
    background: rgba(212, 165, 116, 0.15);
    border: 1px solid rgba(212, 165, 116, 0.3);
    border-radius: var(--radius-full);
}

.hero-title {
    font-size: clamp(var(--font-size-4xl), 6vw, var(--font-size-6xl));
    font-weight: var(--font-weight-bold);
    line-height: 1.1;
    margin-bottom: 1.5rem;
    letter-spacing: -0.03em;
}

.hero-title .highlight {
    display: block;
    background: linear-gradient(135deg, var(--color-secondary) 0%, var(--color-secondary-light) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.hero-description {
    font-size: var(--font-size-lg);
    color: rgba(255, 255, 255, 0.8);
    max-width: 600px;
    margin: 0 auto 2.5rem;
    line-height: 1.7;
}

.hero-buttons {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 1rem;
    margin-bottom: 4rem;
    flex-wrap: wrap;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 0.5rem;
    padding: 1rem 2rem;
    border-radius: var(--radius-full);
    font-size: var(--font-size-base);
    font-weight: var(--font-weight-semibold);
    transition: all var(--transition-base);
    position: relative;
    overflow: hidden;
}

.btn svg {
    flex-shrink: 0;
}

.btn-primary {
    background: var(--color-secondary);
    color: var(--color-dark);
    box-shadow: 0 4px 15px rgba(212, 165, 116, 0.4);
}

.btn-primary:hover {
    background: var(--color-secondary-light);
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);
}

.btn-primary:hover svg {
    transform: translateX(4px);
}

.btn-secondary {
    background: transparent;
    color: var(--color-white);
    border: 2px solid rgba(255, 255, 255, 0.3);
    backdrop-filter: var(--glass-blur);
}

.btn-secondary:hover {
    border-color: var(--color-white);
    background: rgba(255, 255, 255, 0.1);
    transform: translateY(-2px);
}

.btn-outline {
    background: transparent;
    color: var(--color-primary);
    border: 2px solid var(--color-primary);
}

.btn-outline:hover {
    background: var(--color-primary);
    color: var(--color-white);
}

.btn-text {
    padding: 0.5rem;
    color: var(--color-primary);
}

.btn-text:hover {
    color: var(--color-primary-dark);
}

.btn-text:hover svg {
    transform: translateX(4px);
}

.btn-sm {
    padding: 0.625rem 1.25rem;
    font-size: var(--font-size-sm);
}

/* Hero Stats */
.hero-stats {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 2rem;
    padding: 1.5rem 2rem;
    background: var(--glass-bg);
    backdrop-filter: var(--glass-blur);
    border: 1px solid var(--glass-border);
    border-radius: var(--radius-xl);
    flex-wrap: wrap;
}

.stat {
    text-align: center;
}

.stat-number {
    display: block;
    font-size: var(--font-size-2xl);
    font-weight: var(--font-weight-bold);
    color: var(--color-white);
    font-family: var(--font-display);
}

.stat-label {
    font-size: var(--font-size-sm);
    color: rgba(255, 255, 255, 0.6);
}

.stat-divider {
    width: 1px;
    height: 40px;
    background: rgba(255, 255, 255, 0.2);
}

/* Scroll Indicator */
.scroll-indicator {
    position: absolute;
    bottom: 2rem;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    color: rgba(255, 255, 255, 0.5);
    font-size: var(--font-size-xs);
    letter-spacing: 0.1em;
    text-transform: uppercase;
}

.mouse {
    width: 26px;
    height: 40px;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-radius: 13px;
    display: flex;
    justify-content: center;
    padding-top: 8px;
}

.wheel {
    width: 4px;
    height: 8px;
    background: rgba(255, 255, 255, 0.5);
    border-radius: 2px;
    animation: scroll 1.5s ease-in-out infinite;
}

@keyframes scroll {
    0% {
        transform: translateY(0);
        opacity: 1;
    }
    100% {
        transform: translateY(12px);
        opacity: 0;
    }
}

/* ========================================
   FEATURES SECTION
   ======================================== */
.features {
    padding: var(--section-padding) 0;
    background: var(--color-cream);
}

.features-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
}

.feature-card {
    background: var(--color-white);
    padding: 2.5rem;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-card);
    transition: all var(--transition-base);
    text-align: center;
}

.feature-card:hover {
    transform: translateY(-8px);
    box-shadow: var(--shadow-xl);
}

.feature-icon {
    width: 72px;
    height: 72px;
    background: var(--gradient-warm);
    border-radius: var(--radius-xl);
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1.5rem;
    color: var(--color-primary-dark);
}

.feature-card h3 {
    font-size: var(--font-size-xl);
    margin-bottom: 0.75rem;
}

.feature-card p {
    color: var(--color-gray);
    font-size: var(--font-size-base);
    margin: 0;
}

/* ========================================
   ABOUT SECTION
   ======================================== */
.about {
    padding: var(--section-padding) 0;
    background: var(--color-white);
}

.about-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4rem;
    align-items: center;
}

/* About Images */
.about-images {
    position: relative;
}

.image-main {
    border-radius: var(--radius-2xl);
    overflow: hidden;
    box-shadow: var(--shadow-xl);
}

.image-main img {
    width: 100%;
    height: 500px;
    object-fit: cover;
    transition: transform var(--transition-slow);
}

.image-main:hover img {
    transform: scale(1.05);
}

.image-float {
    position: absolute;
    bottom: -40px;
    right: -40px;
    width: 280px;
    border-radius: var(--radius-xl);
    overflow: hidden;
    box-shadow: var(--shadow-xl);
    border: 8px solid var(--color-white);
}

.image-float img {
    width: 100%;
    height: 200px;
    object-fit: cover;
}

.experience-badge {
    position: absolute;
    top: -20px;
    left: -20px;
    background: var(--color-primary);
    color: var(--color-white);
    padding: 1.5rem;
    border-radius: var(--radius-xl);
    text-align: center;
    box-shadow: var(--shadow-lg);
}

.experience-badge .years {
    display: block;
    font-size: var(--font-size-3xl);
    font-weight: var(--font-weight-bold);
    font-family: var(--font-display);
}

.experience-badge .text {
    font-size: var(--font-size-sm);
    line-height: 1.3;
}

/* About Content */
.section-tag {
    display: inline-block;
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-semibold);
    letter-spacing: 0.15em;
    text-transform: uppercase;
    color: var(--color-accent);
    margin-bottom: 1rem;
}

.section-title {
    font-size: clamp(var(--font-size-3xl), 4vw, var(--font-size-4xl));
    margin-bottom: 1.5rem;
    line-height: 1.2;
}

.section-description {
    color: var(--color-gray);
    font-size: var(--font-size-lg);
    line-height: 1.7;
    margin-bottom: 1rem;
}

.about-highlights {
    margin: 2rem 0;
}

.highlight-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    margin-bottom: 0.75rem;
    color: var(--color-dark);
}

.highlight-item svg {
    color: var(--color-accent);
}

/* ========================================
   MENU SECTION
   ======================================== */
.menu {
    padding: var(--section-padding) 0;
    background: var(--color-cream);
}

.section-header {
    text-align: center;
    max-width: 600px;
    margin: 0 auto 3rem;
}

/* Menu Tabs */
.menu-tabs {
    display: flex;
    justify-content: center;
    gap: 0.5rem;
    margin-bottom: 3rem;
    flex-wrap: wrap;
}

.tab-btn {
    padding: 0.75rem 1.5rem;
    border-radius: var(--radius-full);
    font-size: var(--font-size-sm);
    font-weight: var(--font-weight-medium);
    color: var(--color-gray);
    background: transparent;
    border: 1px solid var(--color-gray-light);
    transition: all var(--transition-base);
}

.tab-btn:hover {
    color: var(--color-primary);
    border-color: var(--color-primary);
}

.tab-btn.active {
    background: var(--color-primary);
    color: var(--color-white);
    border-color: var(--color-primary);
}

/* Menu Panels */
.menu-panel {
    display: none;
}

.menu-panel.active {
    display: block;
    animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
    gap: 2rem;
}

/* Menu Item */
.menu-item {
    background: var(--color-white);
    border-radius: var(--radius-xl);
    overflow: hidden;
    box-shadow: var(--shadow-card);
    transition: all var(--transition-base);
}

.menu-item:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-xl);
}

.menu-item-image {
    position: relative;
    height: 200px;
    overflow: hidden;
}

.menu-item-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform var(--transition-slow);
}

.menu-item:hover .menu-item-image img {
    transform: scale(1.1);
}

.add-to-cart {
    position: absolute;
    bottom: 1rem;
    right: 1rem;
    width: 44px;
    height: 44px;
    background: var(--color-white);
    border-radius: var(--radius-full);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: var(--font-size-xl);
    font-weight: var(--font-weight-bold);
    color: var(--color-primary);
    box-shadow: var(--shadow-md);
    transition: all var(--transition-base);
}

.add-to-cart:hover {
    background: var(--color-secondary);
    transform: scale(1.1);
}

.menu-item-content {
    padding: 1.5rem;
}

.menu-item-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.menu-item-header h4 {
    font-size: var(--font-size-lg);
}

.price {
    font-size: var(--font-size-lg);
    font-weight: var(--font-weight-bold);
    color: var(--color-primary);
    font-family: var(--font-display);
}

.menu-item-content p {
    color: var(--color-gray);
    font-size: var(--font-size-sm);
    margin-bottom: 0.75rem;
}

